import React, { useState, useEffect } from 'react';
import { useAuth } from '../../contexts/AuthContext';
import MentorProfileModal from './MentorProfileModal'; // We'll create this component
import './Mentors.css';

const Mentors = () => {
  const [mentors, setMentors] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedDomain, setSelectedDomain] = useState('all');
  const [selectedMentor, setSelectedMentor] = useState(null);
  const [showProfileModal, setShowProfileModal] = useState(false);
  const { user } = useAuth();

  const domains = [
    'all', 'technology', 'business', 'design', 'data-science', 
    'marketing', 'healthcare', 'finance', 'engineering', 
    'creative-arts', 'education', 'entrepreneurship'
  ];

  useEffect(() => {
    fetchMentors();
  }, []);

  const fetchMentors = async () => {
    setLoading(true);
    try {
      const comprehensiveMentors = [
        // Technology Mentors
        {
          id: 1,
          name: 'Sarah Chen',
          title: 'Senior Software Engineer at Google',
          avatar: 'https://images.unsplash.com/photo-1494790108755-2616b612b786?w=150&h=150&fit=crop&crop=face',
          experience: '8 years',
          rating: 4.9,
          sessions: 245,
          specialization: ['Web Development', 'JavaScript', 'React', 'Node.js'],
          bio: 'Full-stack developer with expertise in modern web technologies. Passionate about mentoring junior developers.',
          availability: 'Available',
          company: 'Google',
          platform: 'LinkedIn',
          hourlyRate: '$120',
          domain: 'technology',
          email: 'sarah.chen@example.com',
          linkedin: 'https://linkedin.com/in/sarahchen',
          website: 'https://sarahchen.dev',
          achievements: [
            'Google Peer Bonus Award 2023',
            'Built scalable systems serving 10M+ users',
            'Open source contributor to React ecosystem'
          ],
          education: 'M.S. Computer Science - Stanford University',
          languages: ['JavaScript', 'Python', 'TypeScript', 'Java'],
          tools: ['React', 'Node.js', 'AWS', 'Docker', 'Kubernetes']
        },
        {
          id: 2,
          name: 'Alex Rodriguez',
          title: 'Lead DevOps Engineer at AWS',
          avatar: 'https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?w=150&h=150&fit=crop&crop=face',
          experience: '10 years',
          rating: 4.8,
          sessions: 189,
          specialization: ['Cloud Computing', 'DevOps', 'Kubernetes', 'AWS'],
          bio: 'Cloud infrastructure specialist helping teams scale their applications efficiently.',
          availability: 'Limited',
          company: 'Amazon Web Services',
          platform: 'ADPList',
          hourlyRate: '$150',
          domain: 'technology',
          email: 'alex.rodriguez@example.com',
          linkedin: 'https://linkedin.com/in/alexrodriguez',
          website: 'https://alexrodriguez.cloud',
          achievements: [
            'AWS Certified Solutions Architect',
            'Led migration of 500+ services to Kubernetes',
            'Speaker at AWS re:Invent 2023'
          ],
          education: 'B.S. Computer Engineering - MIT',
          languages: ['Python', 'Go', 'Bash', 'Terraform'],
          tools: ['AWS', 'Kubernetes', 'Docker', 'Jenkins', 'Terraform']
        },
        // ... Add more mentors with complete profile data
      ];
      
      setMentors(comprehensiveMentors);
    } catch (error) {
      console.error('Error fetching mentors:', error);
    } finally {
      setLoading(false);
    }
  };

  const filteredMentors = selectedDomain === 'all' 
    ? mentors 
    : mentors.filter(mentor => mentor.domain === selectedDomain);

  const requestMentorship = (mentorId) => {
    alert(`Mentorship request sent to mentor #${mentorId}`);
    // Here you would typically make an API call
  };

  const viewProfile = (mentor) => {
    setSelectedMentor(mentor);
    setShowProfileModal(true);
  };

  const closeProfileModal = () => {
    setShowProfileModal(false);
    setSelectedMentor(null);
  };

  const getDomainIcon = (domain) => {
    const icons = {
      'technology': '💻',
      'business': '💼',
      'design': '🎨',
      'data-science': '📊',
      'marketing': '📱',
      'healthcare': '🏥',
      'finance': '💰',
      'engineering': '⚙️',
      'creative-arts': '🎭',
      'education': '📚',
      'entrepreneurship': '🚀',
      'all': '👥'
    };
    return icons[domain] || '👥';
  };

  if (!user) {
    return (
      <div className="mentors-container">
        <div className="container">
          <div className="auth-required">
            <h2>Authentication Required</h2>
            <p>Please log in to explore mentors.</p>
          </div>
        </div>
      </div>
    );
  }

  if (loading) {
    return (
      <div className="mentors-container">
        <div className="container">
          <div className="loading">
            <div className="spinner"></div>
            <p>Loading mentors...</p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="mentors-container">
      <div className="container">
        <div className="mentors-header">
          <h1>👥 Find Your Mentor</h1>
          <p>Connect with experienced professionals across various industries and platforms</p>
        </div>

        <div className="mentors-filters">
          <h3>Filter by Domain:</h3>
          <div className="filter-buttons">
            {domains.map(domain => (
              <button
                key={domain}
                className={`filter-btn ${selectedDomain === domain ? 'active' : ''}`}
                onClick={() => setSelectedDomain(domain)}
              >
                {getDomainIcon(domain)} {domain.charAt(0).toUpperCase() + domain.slice(1).replace('-', ' ')}
              </button>
            ))}
          </div>
        </div>

        <div className="mentors-counter">
          <span>{filteredMentors.length} mentors in {selectedDomain === 'all' ? 'All Domains' : selectedDomain.replace('-', ' ')}</span>
        </div>

        <div className="mentors-grid">
          {filteredMentors.map(mentor => (
            <div key={mentor.id} className="mentor-card">
              <div className="mentor-header">
                <img src={mentor.avatar} alt={mentor.name} className="mentor-avatar" />
                <div className="mentor-info">
                  <h3>{mentor.name}</h3>
                  <div className="mentor-title">{mentor.title}</div>
                  <div className="mentor-stats">
                    <span>⭐ {mentor.rating} ({mentor.sessions})</span>
                    <span>💼 {mentor.platform}</span>
                  </div>
                </div>
              </div>

              <div className="mentor-details">
                <p className="mentor-bio">{mentor.bio}</p>
                
                <div className="mentor-specialization">
                  <strong>Specializations:</strong>
                  <div className="specialization-tags">
                    {mentor.specialization.map((skill, index) => (
                      <span key={index} className="specialization-tag">{skill}</span>
                    ))}
                  </div>
                </div>
              </div>

              <div className="mentor-meta">
                <div className="mentor-details-left">
                  <span className="experience">📅 {mentor.experience}</span>
                  <span className="availability">{mentor.availability === 'Available' ? '✅ Available' : '🟡 Limited'}</span>
                </div>
                <div className="mentor-rate">
                  <span className="hourly-rate">{mentor.hourlyRate}/hr</span>
                </div>
              </div>

              <div className="mentor-actions">
                <button 
                  onClick={() => requestMentorship(mentor.id)}
                  className="btn btn-primary"
                >
                  Request Session
                </button>
                <button 
                  onClick={() => viewProfile(mentor)}
                  className="btn btn-outline"
                >
                  View Profile
                </button>
              </div>
            </div>
          ))}
        </div>

        {filteredMentors.length === 0 && (
          <div className="no-mentors">
            <h3>No mentors found in this domain</h3>
            <p>Try selecting a different domain or check back later for new mentors.</p>
          </div>
        )}

        {/* Mentor Profile Modal */}
        {showProfileModal && selectedMentor && (
          <MentorProfileModal 
            mentor={selectedMentor}
            onClose={closeProfileModal}
            onRequestSession={() => requestMentorship(selectedMentor.id)}
          />
        )}
      </div>
    </div>
  );
};

export default Mentors;
